sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.pt-0 {
  padding-top: 0;
}

.panel-embedder {
  /* Target the panel INSIDE the embedder's body */
  .panel-body .panel {
    border: none !important;
    box-shadow: none !important;
    margin-bottom: 0;

    .panel-heading,
    .panel-footer {
      display: none !important;
    }
  }

  /* Target immediate panel-body */
  & > .panel-body {
    padding: 0; 
  }

  .panel-footer {
    background-color: unset !important;
    border-top: none !important;
    text-align: center;
  }
}

sp_widget.script:
(function() {
    // Changed from widget_to_embed to widget_to_display
    var widgetId = options.widget_to_display;
    var params = {};

    // Use the exact name from your schema: u_widget_params
    if (options.u_widget_params) {
        try {
            params = JSON.parse(options.u_widget_params);
        } catch (e) {
            gs.warn("Widget Embedder: Error parsing JSON in u_widget_params. " + e.message);
        }
    }

    if (widgetId) {
        // Pass the parsed params object into the widget
        data.embeddedWidget = $sp.getWidget(widgetId, params);
    }
})();
